        [Test]
        public void Trajectory_MatchesBaseline()
        {
            string actual = RunAndCapture();
            string expected = BaselineCsv.Trim();
            if (expected.Length == 0)
            {
                Assert.Fail(
                    "BaselineCsv is empty. Paste the following between the BaselineCsv quotes " +
                    "in MovementGoldenMasterTests.cs (mind C# verbatim-string @\"...\" escaping " +
                    "of double-quotes; this CSV has none, so it pastes cleanly):\n\n" + actual);
            }
            // Normalize: collapse any whitespace (newlines, spaces, tabs) to single spaces.
            // The CSV values are commas + digits + minus signs only — no whitespace inside a
            // field — so this safely tolerates baselines pasted as one long line (e.g. when
            // copied from Unity Test Runner's XML export) AND newline-formatted baselines.
            Assert.AreEqual(Normalize(expected), Normalize(actual),
                "Movement.Step trajectory drift detected. If the drift is intentional " +
                "(e.g. tuning pass, deliberate feel change), regenerate the baseline via the " +
                "[Explicit] RegenerateBaseline test. Otherwise this is a regression — bisect " +
                "to the commit that broke it.");
        }

        static string Normalize(string s) =>
            string.Join(' ', s.Split(new[] { ' ', '\t', '\n', '\r' },
                System.StringSplitOptions.RemoveEmptyEntries));

        [Test, Explicit]
        public void RegenerateBaseline()
        {
            TestContext.Out.WriteLine(RunAndCapture());
        }

        // ---- Recording ----

        static string RunAndCapture()
        {
            var t = DefaultTuning();
            var w = new FakeFlatGroundWorld();
            var s = new MovementState
            {
                state               = MoveState.Grounded,
                facing              = 1,
                dashChargeAvailable = true,
                posY                = 1f,                            // feet at y=0 in FakeFlatGroundWorld
            };
            var sb = new StringBuilder(64 * Ticks);
            sb.AppendLine("tick,posX,posY,velX,velY,state,facing,coyote,buffer,dashT,invulnT,freezeT,dashCharge,wasHeld,dead,edges");

            for (int tick = 0; tick < Ticks; tick++)
            {
                var input = InputAtTick(tick);
                EdgeFlags edges; (s, edges) = Movement.Step(s, input, t, Dt, w);
                AppendRow(sb, tick, s, edges);
            }
            return sb.ToString();
        }

        // 300-tick scripted sequence covering walk, jump, variable cut, dash + freeze + launch,
        // walk-back, second jump, fall, land. Designed to exercise every reachable branch in
        // Movement.Step at least once.
        static EffectiveInput InputAtTick(int tick)
        {
            // 0..29 — walk right on the ground
            if (tick < 30) return new EffectiveInput { moveDir = 1 };
            // 30 — press jump (edge); 31..49 hold jump
            if (tick == 30) return new EffectiveInput { moveDir = 1, jumpPressed = true, jumpHeld = true };
            if (tick < 50)  return new EffectiveInput { moveDir = 1, jumpHeld = true };
            // 50..79 — release jump mid-air (variable cut), keep walking right
            if (tick < 80)  return new EffectiveInput { moveDir = 1 };
            // 80 — press dash; 81..119 — no input during freeze + motion phase
            if (tick == 80) return new EffectiveInput { dashPressed = true };
            if (tick < 120) return new EffectiveInput();
            // 120..179 — walk left on the ground (lands somewhere in here)
            if (tick < 180) return new EffectiveInput { moveDir = -1 };
            // 180 — press jump again (second jump, to test dash-charge refund on landing); 181..199 hold
            if (tick == 180) return new EffectiveInput { moveDir = -1, jumpPressed = true, jumpHeld = true };
            if (tick < 200)  return new EffectiveInput { moveDir = -1, jumpHeld = true };
            // 200..299 — no input, fall + land
            return new EffectiveInput();
        }

        static MovementTuning DefaultTuning() => new MovementTuning
        {
            runSpeed                    = 9f,
            airControlMultiplier        = 0.85f,
            jumpVelocity                = 16f,
            gravity                     = 50f,
            coyoteTime                  = 0.1f,
            jumpBufferTime              = 0.1f,
            variableJumpCutMultiplier   = 0.5f,
            dashDistance                = 4f,
            dashDuration                = 0.15f,
            dashInvulnerabilityDuration = 0.15f,
            dashFreezeTicks             = 3,
            fallLimitY                  = -20f,
        };

        // F4 (4 decimal places) gives ~5e-5 implicit tolerance on float fields; same-machine
        // same-runtime determinism is bit-exact so F4 strings match identically. If a future Unity
        // version shifts a last-bit float result, F4 absorbs it without flagging.
        static void AppendRow(StringBuilder sb, int tick, MovementState s, EdgeFlags edges)
        {
            var c = CultureInfo.InvariantCulture;
            sb.Append(tick).Append(',');
            sb.Append(s.posX.ToString("F4", c)).Append(',');
            sb.Append(s.posY.ToString("F4", c)).Append(',');
            sb.Append(s.velX.ToString("F4", c)).Append(',');
            sb.Append(s.velY.ToString("F4", c)).Append(',');
            sb.Append((int)s.state).Append(',');
            sb.Append(s.facing).Append(',');
            sb.Append(s.coyoteTimer.ToString("F4", c)).Append(',');
            sb.Append(s.jumpBufferTimer.ToString("F4", c)).Append(',');
            sb.Append(s.dashTimer.ToString("F4", c)).Append(',');
            sb.Append(s.invulnTimer.ToString("F4", c)).Append(',');
            sb.Append(s.freezeTicksRemaining).Append(',');
            sb.Append(s.dashChargeAvailable ? 1 : 0).Append(',');
            sb.Append(s.wasJumpHeld ? 1 : 0).Append(',');
            sb.Append(s.isDead ? 1 : 0).Append(',');
            sb.Append((int)edges);
            sb.AppendLine();
        }
    }
